-- Simple script to update branch_id values for existing subjects\n-- Execute this AFTER running the column addition script\n\n-- Step 1: Check what branches are available\nSELECT 'Available branches:' as info;\nSELECT school_id, branch_id, location_name, status \nFROM school_locations \nWHERE status = 'Active' \nORDER BY school_id, branch_id;\n\n-- Step 2: Check subjects that need branch_id\nSELECT 'Subjects needing branch_id:' as info;\nSELECT \n    school_id,\n    COUNT(*) as subject_count\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = ''\nGROUP BY school_id;\n\n-- Step 3: Update branch_id for each school\n-- MODIFY THESE STATEMENTS WITH YOUR ACTUAL SCHOOL AND BRANCH IDs\n\n-- Example updates (UNCOMMENT AND MODIFY AS NEEDED):\n\n-- For school SCH/1, use branch BRCH00001:\n-- UPDATE subjects SET branch_id = 'BRCH00001' WHERE school_id = 'SCH/1' AND (branch_id IS NULL OR branch_id = '');\n\n-- For school SCH/2, use branch BRCH00002:\n-- UPDATE subjects SET branch_id = 'BRCH00002' WHERE school_id = 'SCH/2' AND (branch_id IS NULL OR branch_id = '');\n\n-- Add more UPDATE statements for your other schools...\n\n-- Step 4: Automatic update using first available branch per school\n-- UNCOMMENT THE FOLLOWING IF YOU WANT AUTOMATIC ASSIGNMENT:\n\n/*\nUPDATE subjects s\nSET s.branch_id = (\n    SELECT MIN(sl.branch_id)\n    FROM school_locations sl\n    WHERE sl.school_id = s.school_id\n    AND sl.status = 'Active'\n    LIMIT 1\n)\nWHERE s.branch_id IS NULL OR s.branch_id = '';\n*/\n\n-- Step 5: Verification\nSELECT 'Verification - subjects without branch_id (should be 0):' as check_result;\nSELECT COUNT(*) as subjects_without_branch_id\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 6: Show distribution\nSELECT 'Subject distribution by school and branch:' as distribution;\nSELECT \n    s.school_id,\n    s.branch_id,\n    COUNT(*) as subject_count\nFROM subjects s\nWHERE s.branch_id IS NOT NULL AND s.branch_id != ''\nGROUP BY s.school_id, s.branch_id\nORDER BY s.school_id, s.branch_id;\n\n-- Step 7: Final check\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN 'SUCCESS: All subjects have branch_id!'\n        ELSE CONCAT('ERROR: ', COUNT(*), ' subjects still need branch_id!')\n    END as final_status\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n"